// Extract sensor readings and build a prompt for the maintenance-predictor agent
var sensor = msg.topic.split('/')[2];
var data = msg.payload;

msg.topic = 'maintenance-predictor';
msg.payload = {
    text: `Analyze sensor ${sensor} readings: vibration=${data.vibration || 'N/A'} mm/s, temperature=${data.temperature || 'N/A'}°C, current=${data.current || 'N/A'}A, rpm=${data.rpm || 'N/A'}. Assess failure risk 0-100 and recommend action.`
};
msg.context = {
    sensor_id: sensor,
    raw_data: data,
    timestamp: new Date().toISOString()
};
return msg;

// Parse agent response for risk score
var response = msg.payload.payload || msg.payload;
var riskMatch = String(response).match(/(\d+)\s*\/\s*100|risk[:\s]*(\d+)/i);
var risk = riskMatch ? parseInt(riskMatch[1] || riskMatch[2]) : 0;

msg.risk = risk;
msg.payload = {
    risk: risk,
    agent_response: response,
    sensor_id: (msg.payload.mascarade || {}).context ? msg.payload.mascarade.context.sensor_id : 'unknown',
    timestamp: new Date().toISOString()
};

// Route: output 0 = risk > 70 (alert), output 1 = risk <= 70 (log only)
if (risk > 70) {
    return [msg, null];
} else {
    return [null, msg];
}

msg.payload = {
    level: 'CRITICAL',
    title: `Maintenance Alert — Sensor ${msg.payload.sensor_id}`,
    risk: msg.payload.risk,
    message: msg.payload.agent_response,
    timestamp: msg.payload.timestamp
};
msg.topic = 'factory/alerts/maintenance';
return msg;

var query = msg.payload.question || msg.payload.text || msg.payload;
msg.topic = 'factory-copilot';
msg.payload = {
    text: String(query)
};
msg.context = {
    operator: msg.payload.operator || 'anonymous',
    station: msg.payload.station || 'unknown'
};
return msg;

msg.payload = {
    answer: msg.payload.payload || msg.payload,
    agent: 'factory-copilot',
    timestamp: new Date().toISOString()
};
return msg;

// Calculate shift window (last 8 hours)
var now = new Date();
var shiftStart = new Date(now.getTime() - 8 * 60 * 60 * 1000);

msg.topic = 'log-analyst';
msg.payload = {
    text: `Generate a shift report for the period ${shiftStart.toISOString()} to ${now.toISOString()}. Summarize: production counts, downtime events, quality alerts, safety incidents. Format as a structured shift handover report.`
};
msg.context = {
    shift_start: shiftStart.toISOString(),
    shift_end: now.toISOString(),
    report_type: 'shift_handover'
};
return msg;

var report = msg.payload.payload || msg.payload;
msg.payload = {
    report: report,
    generated_at: new Date().toISOString(),
    shift_end: (msg.payload.mascarade || {}).context ? msg.payload.mascarade.context.shift_end : new Date().toISOString()
};
msg.topic = 'factory/reports/shift';
return msg;

// Placeholder: connect an e-mail node downstream to send the shift report
msg.topic = 'Shift Report — ' + new Date().toLocaleDateString();
msg.payload = msg.payload.report;
return msg;
